export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      let premium = 0;
      for (const item of step.items) {
        if (item.type === "sword") {
          premium += 100;
        }
      }
      premium = Math.ceil(premium * 1.10);
      premium += 5;
      return { premium };
    }
  });
  return { results };
}

