import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should return base premium plus processing fee for a single sword", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({
        results: [{ premium: 115 }],
      });
    });
    it("should return correct base premium for each item type (amulet, staff, potion)", () => {
      const quote = (type: string) => processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type, material: "silver", enchantment: 0, cursed: false }] }],
      });
      expect(quote("amulet")).toEqual({ results: [{ premium: 71 }] });
      expect(quote("staff")).toEqual({ results: [{ premium: 93 }] });
      expect(quote("potion")).toEqual({ results: [{ premium: 49 }] });
    });
    it.todo("should sum premiums for multiple different items");
    it.todo("should charge 25G base premium per component");
    it.todo("should charge 60G for a building block of 3 alike components");
    it.todo("should add 50% surcharge for cursed items");
    it.todo("should add 30% surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply both cursed and enchantment surcharges when both apply");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should add 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should round amounts in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse enchantment >= 8 items at 50% of damage amount");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should track remaining cap across multiple claims on the same policy");
  });
});

