function ceilPercent(amount: number, percent: number): number {
  return Math.ceil(amount * percent / 100);
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100, amulet: 60, staff: 80, potion: 40,
};

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      let premium = 0;
      for (const item of step.items) {
        premium += BASE_PREMIUMS[item.type] ?? 0;
      }
      premium += ceilPercent(premium, 10);
      premium += 5;
      return { premium };
    }
  });
  return { results };
}

