  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      const isFirstQuote = quoteCount === 0;
      quoteCount++;
      const insuranceSum = calculateInsuranceSum(step.items);
